// Verify the HMAC signature the gov-hub dispatcher attached
// in X-Insidellm-Signature. Secret lives in the N8N_WEBHOOK_SECRET env.
//
// Signed body is the *canonicalized* JSON the dispatcher sent:
//   JSON.stringify(inputs, Object.keys(inputs).sort()) with no spaces
// but since we receive the already-parsed body, we re-canonicalize here.

const crypto = require('crypto');

const secret = $env.N8N_WEBHOOK_SECRET || '';
const providedSig = $input.item.binary
  ? undefined
  : ($input.item.json.headers?.['x-insidellm-signature']
     || $input.item.json.headers?.['X-Insidellm-Signature']);

const body = $input.item.json.body || $input.item.json;
const canon = JSON.stringify(
  body,
  Object.keys(body).sort(),
);

const expected = crypto
  .createHmac('sha256', secret)
  .update(canon)
  .digest('hex');

if (!secret) {
  // Fail-open only in dev; production workflows should refuse unsigned.
  return { json: { ok: false, reason: 'no N8N_WEBHOOK_SECRET configured' } };
}
if (!providedSig || providedSig !== expected) {
  return { json: { ok: false, reason: 'invalid signature' } };
}
return { json: { ok: true, body } };
